1	package codex
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os"
7		"path/filepath"
8		"time"
9	
10		"github.com/easel/fizeau/internal/harnesses"
11		"github.com/easel/fizeau/internal/productinfo"
12		"github.com/easel/fizeau/internal/safefs"
13	)
14	
15	// CodexQuotaSnapshot captures Codex subscription quota windows in a durable
16	// cache so foreground service status calls do not need to spawn a live PTY probe.
17	type CodexQuotaSnapshot struct {
18		CapturedAt time.Time               `json:"captured_at"`
19		Windows    []harnesses.QuotaWindow `json:"windows"`
20		Source     string                  `json:"source"`
21		Account    *harnesses.AccountInfo  `json:"account,omitempty"`
22	}
23	
24	const DefaultCodexQuotaStaleAfter = 15 * time.Minute
25	
26	const codexQuotaCacheEnv = "FIZEAU_CODEX_QUOTA_CACHE"
27	
28	// CodexQuotaCachePath returns the durable location for the Codex quota cache.
29	func CodexQuotaCachePath() (string, error) {
30		if path := os.Getenv(codexQuotaCacheEnv); path != "" {
31			return path, nil
32		}
33		if xdg := os.Getenv("XDG_STATE_HOME"); xdg != "" {
34			return filepath.Join(xdg, productinfo.ConfigDir, "codex-quota.json"), nil
35		}
36		home, err := os.UserHomeDir()
37		if err != nil {
38			return "", err
39		}
40		return filepath.Join(home, ".local", "state", productinfo.ConfigDir, "codex-quota.json"), nil
41	}
42	
43	// WriteCodexQuota atomically persists a CodexQuotaSnapshot to path.
44	func WriteCodexQuota(path string, snapshot CodexQuotaSnapshot) error {
45		if path == "" {
46			return fmt.Errorf("codex quota cache path is empty")
47		}
48		if snapshot.CapturedAt.IsZero() {
49			snapshot.CapturedAt = time.Now().UTC()
50		} else {
51			snapshot.CapturedAt = snapshot.CapturedAt.UTC()
52		}
53		if snapshot.Source == "" {
54			snapshot.Source = "pty"
55		}
56		if snapshot.Account == nil {
57			if account, ok := ReadCodexAccount(); ok {
58				snapshot.Account = account
59			}
60		}
61		if err := os.MkdirAll(filepath.Dir(path), 0o750); err != nil {
62			return fmt.Errorf("create codex quota cache dir: %w", err)
63		}
64		data, err := json.MarshalIndent(snapshot, "", "  ")
65		if err != nil {
66			return fmt.Errorf("marshal codex quota snapshot: %w", err)
67		}
68		data = append(data, '\n')
69		tmpPath := path + ".tmp"
70		if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
71			return fmt.Errorf("write codex quota cache tmp: %w", err)
72		}
73		if err := os.Rename(tmpPath, path); err != nil {
74			_ = os.Remove(tmpPath)
75			return fmt.Errorf("rename codex quota cache: %w", err)
76		}
77		if err := os.Chmod(path, 0o600); err != nil {
78			return fmt.Errorf("chmod codex quota cache: %w", err)
79		}
80		return nil
81	}
82	
83	// ReadCodexQuotaFrom reads one Codex quota snapshot.
84	func ReadCodexQuotaFrom(path string) (*CodexQuotaSnapshot, bool) {
85		data, err := safefs.ReadFile(path)
86		if err != nil {
87			return nil, false
88		}
89		var snap CodexQuotaSnapshot
90		if err := json.Unmarshal(data, &snap); err != nil {
91			return nil, false
92		}
93		return &snap, true
94	}
95	
96	// ReadCodexQuota reads the default Codex quota cache.
97	func ReadCodexQuota() (*CodexQuotaSnapshot, bool) {
98		path, err := CodexQuotaCachePath()
99		if err != nil {
100			return nil, false
101		}
102		return ReadCodexQuotaFrom(path)
103	}
104	
105	// CodexQuotaSnapshotAge reports snapshot age relative to now.
106	func CodexQuotaSnapshotAge(snapshot *CodexQuotaSnapshot, now time.Time) time.Duration {
107		if snapshot == nil || snapshot.CapturedAt.IsZero() {
108			return 0
109		}
110		age := now.UTC().Sub(snapshot.CapturedAt.UTC())
111		if age < 0 {
112			return 0
113		}
114		return age
115	}
116	
117	// IsCodexQuotaFresh reports whether a snapshot is present and fresh.
118	func IsCodexQuotaFresh(snapshot *CodexQuotaSnapshot, now time.Time, staleAfter time.Duration) bool {
119		if snapshot == nil || snapshot.CapturedAt.IsZero() {
120			return false
121		}
122		if staleAfter <= 0 {
123			staleAfter = DefaultCodexQuotaStaleAfter
124		}
125		return CodexQuotaSnapshotAge(snapshot, now) <= staleAfter
126	}
127	
128	// CodexQuotaRoutingDecision summarises whether foreground routing may select
129	// Codex without probing the CLI inline.
130	type CodexQuotaRoutingDecision struct {
131		PreferCodex     bool
132		SnapshotPresent bool
133		Fresh           bool
134		Age             time.Duration
135		Snapshot        *CodexQuotaSnapshot
136		Reason          string
137	}
138	
139	// DecideCodexQuotaRouting turns a durable quota snapshot into a foreground
140	// routing decision. Missing, stale, empty, or blocked quota evidence keeps
141	// Codex out of automatic routing; explicit Harness=codex remains available.
142	func DecideCodexQuotaRouting(snapshot *CodexQuotaSnapshot, now time.Time, staleAfter time.Duration) CodexQuotaRoutingDecision {
143		decision := CodexQuotaRoutingDecision{Snapshot: snapshot}
144		if snapshot == nil {
145			decision.Reason = "no cached snapshot; assume limited"
146			return decision
147		}
148		decision.SnapshotPresent = true
149		decision.Age = CodexQuotaSnapshotAge(snapshot, now)
150		if !IsCodexQuotaFresh(snapshot, now, staleAfter) {
151			decision.Reason = "cached snapshot is stale; assume limited"
152			return decision
153		}
154		decision.Fresh = true
155		if len(snapshot.Windows) == 0 {
156			decision.Reason = "fresh snapshot has no quota windows; assume limited"
157			return decision
158		}
159		if !codexAccountSupportsAutoRouting(snapshot.Account) {
160			decision.Reason = "fresh snapshot has no subsidized account plan; assume limited"
161			return decision
162		}
163		for _, window := range snapshot.Windows {
164			if window.State == "blocked" || window.UsedPercent >= 95 {
165				decision.Reason = "fresh snapshot reports blocked window; assume limited"
166				return decision
167			}
168		}
169		decision.PreferCodex = true
170		decision.Reason = "fresh snapshot has headroom"
171		return decision
172	}
173	
174	// ReadCodexQuotaRoutingDecision reads the default cache and produces a routing
175	// decision in one call.
176	func ReadCodexQuotaRoutingDecision(now time.Time, staleAfter time.Duration) CodexQuotaRoutingDecision {
177		snap, _ := ReadCodexQuota()
178		return DecideCodexQuotaRouting(snap, now, staleAfter)
179	}
