18	// CodexAuthPath returns the local Codex auth file used for account metadata.
19	func CodexAuthPath() (string, error) {
20		if path := os.Getenv(codexAuthPathEnv); path != "" {
21			return path, nil
22		}
23		if home := os.Getenv("CODEX_HOME"); home != "" {
24			return filepath.Join(home, "auth.json"), nil
25		}
26		home, err := os.UserHomeDir()
27		if err != nil {
28			return "", err
29		}
30		return filepath.Join(home, ".codex", "auth.json"), nil
31	}
