33	// ReadCodexAccount extracts non-secret account metadata from Codex auth state.
34	func ReadCodexAccount() (*harnesses.AccountInfo, bool) {
35		path, err := CodexAuthPath()
36		if err != nil {
37			return nil, false
38		}
39		return ReadCodexAccountFrom(path)
40	}
