216	// ResolveModelAlias implements harnesses.ModelDiscoveryHarness. Returns
217	// harnesses.ErrAliasNotResolvable when the supplied family is not a
218	// recognized codex alias or when the supplied discovery snapshot has
219	// no concrete model matching the family.
220	func (r *Runner) ResolveModelAlias(family string, snapshot harnesses.ModelDiscoverySnapshot) (string, error) {
221		normalized := strings.ToLower(strings.TrimSpace(family))
222		if !isSupportedCodexAlias(normalized) {
223			return "", harnesses.ErrAliasNotResolvable
224		}
225		resolved := ResolveCodexModelAlias(normalized, snapshot)
226		if resolved == "" || resolved == normalized {
227			// existing helper returns the input string when no concrete
228			// model matches; treat that as unresolvable per CONTRACT-004.
229			return "", harnesses.ErrAliasNotResolvable
230		}
231		return resolved, nil
232	}
