33		if filter.Harness != "" && harnesses.ResolveHarnessAlias(filter.Harness) != "fiz" {
34			return s.listModelsForSubprocessHarness(filter), nil
35		}
36	
37		sc := s.opts.ServiceConfig
38		if sc == nil {
39			return nil, fmt.Errorf("service: no ServiceConfig provided; pass ServiceOptions.ServiceConfig")
40		}
