42	// ReadCodexAccountFrom reads auth.json and extracts email, plan, and org info.
43	func ReadCodexAccountFrom(path string) (*harnesses.AccountInfo, bool) {
44		data, err := safefs.ReadFile(path)
45		if err != nil {
46			return nil, false
47		}
48		var auth struct {
49			Tokens struct {
50				IDToken string `json:"id_token"`
51			} `json:"tokens"`
52			OpenAIAPIKey string `json:"OPENAI_API_KEY"`
53		}
54		if err := json.Unmarshal(data, &auth); err != nil {
55			return nil, false
56		}
57		if auth.Tokens.IDToken != "" {
58			if account, ok := codexAccountFromIDToken(auth.Tokens.IDToken); ok {
59				return account, true
60			}
61		}
62		if auth.OpenAIAPIKey != "" {
63			return &harnesses.AccountInfo{PlanType: "OpenAI API key"}, true
64		}
65		return nil, false
