221	func snapshotFromDiscoveryRecord(rec cassette.DiscoveryRecord) harnesses.ModelDiscoverySnapshot {
222		capturedAt, _ := time.Parse(time.RFC3339, rec.CapturedAt)
223		detail, _ := rec.Metadata["detail"].(string)
224		return harnesses.ModelDiscoverySnapshot{
225			CapturedAt:      capturedAt,
226			Models:          append([]string(nil), rec.Models...),
227			ReasoningLevels: append([]string(nil), rec.ReasoningLevels...),
228			Source:          rec.Source,
229			FreshnessWindow: rec.FreshnessWindow,
230			Detail:          detail,
231		}
232	}
233	
234	func uniqueMatches(values []string) []string {
235		seen := map[string]bool{}
236		out := make([]string, 0, len(values))
237		for _, value := range values {
238			value = strings.TrimSpace(value)
239			if value == "" || seen[value] {
240				continue
241			}
242			seen[value] = true
243			out = append(out, value)
244		}
245		return out
246	}
