14	// codexQuotaFreshness is the constant freshness window for codex quota
15	// evidence. Mirrors DefaultCodexQuotaStaleAfter (kept as a separate name
16	// so the CONTRACT-004 method has a stable, contract-named constant).
17	const codexQuotaFreshness = DefaultCodexQuotaStaleAfter
18	
19	// codexAccountFreshness is the constant freshness window for codex
20	// account evidence. Codex reads account metadata from auth.json which
21	// changes only on re-auth, so a long window is appropriate.
22	const codexAccountFreshness = 7 * 24 * time.Hour
23	
24	// supportedLimitIDs is the stable public set of Windows[].LimitID values
25	// codex's quota probes emit. Mirrored in doc.go for human readers.
26	var supportedLimitIDs = []string{
27		"codex",
28		"codex-weekly",
29	}
30	
31	// supportedAliases is the stable public set of family aliases
32	// ResolveModelAlias recognizes. Mirrored in doc.go for human readers.
33	var supportedAliases = []string{"gpt", "gpt-5"}
34	
35	// refreshGroup serializes concurrent RefreshQuota / RefreshAccount calls
36	// across all *Runner instances. Per CONTRACT-004 invariant #6 Runners are
37	// stateless wrappers — sharing the singleflight group at package scope
38	// keeps single-flight semantics correct when callers construct fresh
39	// runner instances per call (which the dispatcher does today).
40	var refreshGroup singleflight.Group
41	
42	// QuotaStatus implements harnesses.QuotaHarness. It reads the cached
43	// snapshot owned by this harness and projects it onto QuotaStatus. A
44	// missing or undecodable cache is reported as State=QuotaUnavailable on
45	// a valid QuotaStatus value (no error) per CONTRACT-004 §"Errors are
46	// reserved for call failure."
47	func (r *Runner) QuotaStatus(ctx context.Context, now time.Time) (harnesses.QuotaStatus, error) {
48		if err := ctx.Err(); err != nil {
49			return harnesses.QuotaStatus{}, err
50		}
51		snap, ok := ReadCodexQuota()
52		if !ok || snap == nil {
53			return harnesses.QuotaStatus{
54				Source:            "cache",
55				State:             harnesses.QuotaUnavailable,
56				RoutingPreference: harnesses.RoutingPreferenceUnknown,
57				Reason:            "no cached snapshot",
58			}, nil
59		}
60		return codexQuotaStatusFromSnapshot(snap, now), nil
61	}
62	
63	// RefreshQuota implements harnesses.QuotaHarness. It probes the codex
64	// CLI via PTY first and folds the session-token-count source in as an
65	// internal fallback when the PTY probe yields no evidence. The result
66	// is persisted through the harness's owned cache. Single-flight per
67	// harness: concurrent callers share one cohort and observe the
68	// just-written cached state. Probe failure is reported as
69	// State=QuotaUnavailable on a valid QuotaStatus value, not as an error.
70	func (r *Runner) RefreshQuota(ctx context.Context) (harnesses.QuotaStatus, error) {
71		if err := ctx.Err(); err != nil {
72			return harnesses.QuotaStatus{}, err
73		}
74		v, err, _ := refreshGroup.Do("refresh-quota", func() (any, error) {
75			return r.refreshQuotaLocked(ctx), nil
76		})
77		if err != nil {
78			return harnesses.QuotaStatus{}, err
79		}
80		return v.(harnesses.QuotaStatus), nil
81	}
82	
83	// refreshQuotaLocked is the single-flight critical section. It runs the
84	// PTY probe, falls back to the session-token-count source when PTY
85	// yields no evidence, writes the cache on success, and returns the
86	// projected status. Total probe failure is folded into
87	// State=QuotaUnavailable.
88	func (r *Runner) refreshQuotaLocked(ctx context.Context) harnesses.QuotaStatus {
89		now := time.Now()
90		timeout := codexQuotaFreshness
91		if deadline, ok := ctx.Deadline(); ok {
92			remaining := time.Until(deadline)
93			if remaining > 0 && remaining < timeout {
94				timeout = remaining
95			}
96		}
97		var opts []QuotaPTYOption
98		if r.Binary != "" {
99			opts = append(opts, WithQuotaPTYCommand(r.Binary))
100		}
101		windows, _, ptyErr := captureCodexQuotaViaPTY(ctx, timeout, opts...)
102		if ptyErr == nil && len(windows) > 0 {
103			snap := CodexQuotaSnapshot{
104				CapturedAt: now.UTC(),
105				Windows:    windows,
106				Source:     "pty",
107				Account:    readCodexAccountOrNil(),
108			}
109			if path, pathErr := CodexQuotaCachePath(); pathErr == nil {
110				_ = WriteCodexQuota(path, snap)
111			}
112			return codexQuotaStatusFromSnapshot(&snap, now)
113		}
114		if snap, ok := ReadCodexQuotaFromSessionTokenCounts(WithCodexSessionTokenCountNow(now)); ok && snap != nil {
115			if snap.Account == nil {
116				snap.Account = readCodexAccountOrNil()
117			}
118			if path, pathErr := CodexQuotaCachePath(); pathErr == nil {
119				_ = WriteCodexQuota(path, *snap)
120			}
121			return codexQuotaStatusFromSnapshot(snap, now)
122		}
123		state := harnesses.QuotaUnavailable
124		reason := "no quota evidence from PTY probe or session token-count fallback"
125		if ptyErr != nil {
126			reason = ptyErr.Error()
127			lower := strings.ToLower(reason)
128			if strings.Contains(lower, "not found in path") || strings.Contains(lower, "executable file not found") {
129				state = harnesses.QuotaUnauthenticated
130			}
131		}
132		return harnesses.QuotaStatus{
133			Source:            "pty",
134			CapturedAt:        now.UTC(),
135			State:             state,
136			RoutingPreference: harnesses.RoutingPreferenceUnknown,
137			Reason:            reason,
138		}
139	}
