183	// readCodexAccountSnapshot reads codex auth state and projects it onto
184	// AccountSnapshot. A missing or unreadable auth file is reported as
185	// Unauthenticated on a valid snapshot value, not as an error.
186	func readCodexAccountSnapshot(now time.Time) harnesses.AccountSnapshot {
187		snap := harnesses.AccountSnapshot{Source: "cache"}
188		if path, err := CodexAuthPath(); err == nil && path != "" {
189			snap.Source = path
190			if st, statErr := os.Stat(path); statErr == nil {
191				snap.CapturedAt = st.ModTime().UTC()
192				snap.Fresh = now.UTC().Sub(snap.CapturedAt) <= codexAccountFreshness
193			}
194		}
195		account, ok := ReadCodexAccount()
196		if !ok || account == nil {
197			snap.Unauthenticated = true
198			return snap
199		}
200		snap.Email = account.Email
201		snap.PlanType = account.PlanType
202		snap.OrgName = account.OrgName
203		if strings.TrimSpace(account.PlanType) == "" {
204			snap.Unauthenticated = true
205		} else {
206			snap.Authenticated = true
207		}
208		return snap
209	}
