19	const defaultEventBuffer = 64
20	
21	// Fallback only: unpinned runs resolve through model discovery first.
22	const fallbackDefaultModel = "gpt-5.4"
23	
24	// Runner is the subprocess-backed codex harness. It launches codex in
25	// exec --json mode, parses each JSONL line into harness Events, and emits
26	// a final Event when the subprocess exits.
27	type Runner struct {
28		// Binary is the absolute path to the codex executable. When empty the
29		// runner resolves "codex" via PATH at Execute time.
30		Binary string
31	
32		// BaseArgs is prepended to the per-request argument list.
33		// Codex default: ["exec", "--json"]
34		BaseArgs []string
35	
36		// PromptMode controls how the prompt is delivered:
37		//   "arg" (default) — prompt is appended as the final positional argument
38		//   "stdin"         — prompt is piped on stdin
39		PromptMode string
40	
41		// EventBuffer overrides the per-Execute channel buffer size.
42		EventBuffer int
43	
44		// DiscoveryCache overrides model/reasoning discovery evidence in tests.
45		DiscoveryCache *harnesses.ModelDiscoveryCache
46	}
47	
48	// Info returns identity + capability metadata for this harness.
49	func (r *Runner) Info() harnesses.HarnessInfo {
50		info := harnesses.HarnessInfo{
51			Name:                 "codex",
52			Type:                 "subprocess",
53			IsLocal:              false,
54			IsSubscription:       true,
55			AutoRoutingEligible:  true,
56			ExactPinSupport:      true,
57			DefaultModel:         harnesses.ResolveRunnerModel("codex", modelcatalog.SurfaceCodex, "", fallbackDefaultModel).ResolvedModel,
58			SupportedPermissions: []string{"safe", "supervised", "unrestricted"},
59			SupportedReasoning:   []string{"low", "medium", "high", "xhigh", "max"},
60			CostClass:            "medium",
61		}
62		path := r.Binary
63		if path == "" {
64			if resolved, err := osexec.LookPath("codex"); err == nil {
65				path = resolved
66			}
67		}
68		if path != "" {
69			info.Path = path
70			info.Available = true
71		} else {
72			info.Error = "codex binary not found in PATH"
73		}
74		return info
75	}
76	
77	// HealthCheck verifies the codex binary is present.
78	func (r *Runner) HealthCheck(ctx context.Context) error {
79		if err := ctx.Err(); err != nil {
80			return err
81		}
82		path := r.Binary
83		if path == "" {
84			resolved, err := osexec.LookPath("codex")
85			if err != nil {
86				return fmt.Errorf("codex binary not found: %w", err)
87			}
88			path = resolved
89		}
90		st, err := os.Stat(path)
91		if err != nil {
92			return fmt.Errorf("stat codex binary: %w", err)
93		}
94		if st.IsDir() {
95			return fmt.Errorf("codex binary path is a directory: %s", path)
96		}
97		return nil
98	}
99	
100	// Execute runs one resolved request through the codex CLI and emits
101	// JSONL-derived events on the returned channel.
102	func (r *Runner) Execute(ctx context.Context, req harnesses.ExecuteRequest) (<-chan harnesses.Event, error) {
103		binary := r.Binary
104		if binary == "" {
105			resolved, err := osexec.LookPath("codex")
106			if err != nil {
107				return nil, fmt.Errorf("codex binary not found: %w", err)
108			}
109			binary = resolved
110		}
111	
112		bufSize := r.EventBuffer
113		if bufSize <= 0 {
114			bufSize = defaultEventBuffer
115		}
116	
117		out := make(chan harnesses.Event, bufSize)
118		go r.run(ctx, binary, req, out)
119		return out, nil
120	}
121	
122	func (r *Runner) run(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event) {
123		defer close(out)
124	
125		start := time.Now()
126		var seq int64
127	
128		agg, exitCode, stderr, runErr, status := r.runStreaming(ctx, binary, req, out, &seq)
129	
130		final := harnesses.FinalData{
131			Status:     status,
132			ExitCode:   exitCode,
133			DurationMS: time.Since(start).Milliseconds(),
134		}
135		reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "codex", req.Reasoning)
136		if harnesses.ShouldEmitRunnerReasoningResolution(reasoningResolution) {
137			final.Reasoning = &reasoningResolution
138		}
139		if runErr != nil && status != "success" {
140			final.Error = runErr.Error()
141		} else if stderr != "" && status != "success" {
142			final.Error = trimErrorBlob(stderr)
143		}
144		if agg != nil {
145			final.FinalText = agg.FinalText
146			final.Usage, final.Warnings = harnesses.ResolveFinalUsage(agg.UsageSources)
147			agg.writeTokenCountQuotaCache()
148		}
149	
150		finalRaw, err := json.Marshal(final)
151		if err != nil {
152			finalRaw = []byte(`{"status":"failed","error":"marshal final event"}`)
153		}
154		ev := harnesses.Event{
155			Type:     harnesses.EventTypeFinal,
156			Sequence: seq,
157			Time:     time.Now().UTC(),
158			Metadata: req.Metadata,
159			Data:     finalRaw,
160		}
161		select {
162		case out <- ev:
163		case <-time.After(time.Second):
164		}
165	}
166	
167	func (a *streamAggregate) writeTokenCountQuotaCache() {
168		if a == nil || len(a.TokenCountRateLimits) == 0 {
169			return
170		}
171		var newest *CodexQuotaSnapshot
172		for _, evidence := range a.TokenCountRateLimits {
173			fallback := time.Now().UTC()
174			snapshot, ok := CodexQuotaSnapshotFromTokenCountRateLimits(evidence.CapturedAt, fallback, evidence.RateLimits)
175			if !ok {
176				continue
177			}
178			snapshot.Source = "codex_exec_token_count"
179			if newest == nil || snapshot.CapturedAt.After(newest.CapturedAt) {
180				newest = snapshot
181			}
182		}
183		if newest == nil {
184			return
185		}
186		path, err := CodexQuotaCachePath()
187		if err != nil {
188			return
189		}
190		_ = WriteCodexQuota(path, *newest)
191	}
192	
193	func (r *Runner) runStreaming(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event, seq *int64) (agg *streamAggregate, exitCode int, stderr string, runErr error, status string) {
194		base := r.BaseArgs
195		if base == nil {
196			base = []string{"exec", "--json"}
197		}
198		args := append([]string{}, base...)
199		modelResolution := harnesses.ResolveRunnerModelWithCache(r.DiscoveryCache, "codex", modelcatalog.SurfaceCodex, req.Model, fallbackDefaultModel)
200		reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "codex", req.Reasoning)
201	
202		// Permission args: unrestricted adds --dangerously-bypass-approvals-and-sandbox
203		if req.Permissions == "unrestricted" {
204			args = append(args, "--dangerously-bypass-approvals-and-sandbox")
205		}
206	
207		// WorkDir flag: -C <dir>
208		if req.WorkDir != "" {
209			args = append(args, "-C", req.WorkDir)
210		}
211	
212		// Model flag: -m <model>
213		if modelResolution.ResolvedModel != "" {
214			args = append(args, "-m", modelResolution.ResolvedModel)
215		}
216	
217		// Reasoning flag: -c reasoning.effort=<reasoning>
218		if value := reasoningResolution.ResolvedReasoning; value != "" {
219			args = append(args, "-c", fmt.Sprintf("reasoning.effort=%s", value))
220		}
221	
222		promptMode := r.PromptMode
223		if promptMode == "" {
224			promptMode = "arg"
225		}
226		if promptMode == "arg" && req.Prompt != "" {
227			args = append(args, req.Prompt)
228		}
229	
230		runCtx, cancel := context.WithCancel(ctx)
231		defer cancel()
232	
233		cmd := harnesses.HarnessCommand(runCtx, binary, args...)
234		if req.WorkDir != "" {
235			cmd.Dir = req.WorkDir
236		}
237		if promptMode != "arg" {
238			cmd.Stdin = strings.NewReader(req.Prompt)
239		}
240		setProcessGroup(cmd)
241	
242		stdoutPipe, err := cmd.StdoutPipe()
243		if err != nil {
244			return nil, -1, "", err, "failed"
245		}
246		stderrPipe, err := cmd.StderrPipe()
247		if err != nil {
248			return nil, -1, "", err, "failed"
249		}
250	
251		if err := cmd.Start(); err != nil {
252			return nil, -1, "", err, "failed"
253		}
254	
255		progressLog, _ := harnesses.OpenProgressLog(req.SessionLogDir, req.SessionID, "codex")
256		if progressLog != nil {
257			defer progressLog.Close()
258		}
259		if harnesses.ShouldEmitRunnerDefaultResolution(modelResolution) {
260			ev := harnesses.RunnerDefaultResolutionEvent(modelResolution, req.Metadata, seq)
261			harnesses.WriteProgressEvent(progressLog, ev)
262			select {
263			case out <- ev:
264			case <-ctx.Done():
265				return nil, -1, "", ctx.Err(), "cancelled"
266			}
267		}
268		if harnesses.ShouldEmitRunnerReasoningResolution(reasoningResolution) {
269			harnesses.LogRunnerReasoningWarning(reasoningResolution)
270			ev := harnesses.RunnerReasoningResolutionEvent(reasoningResolution, req.Metadata, seq)
271			harnesses.WriteProgressEvent(progressLog, ev)
272			select {
273			case out <- ev:
274			case <-ctx.Done():
275				return nil, -1, "", ctx.Err(), "cancelled"
276			}
277		}
278	
279		parserReader, parserWriter := io.Pipe()
280		parseDone := make(chan struct{})
281		var parseAgg *streamAggregate
282		var parseErr error
283		go func() {
284			defer close(parseDone)
285			mirrored, mirrorDone := harnesses.MirrorEvents(out, progressLog, ctx)
286			defer func() {
287				close(mirrored)
288				<-mirrorDone
289			}()
290			parseAgg, parseErr = parseCodexStream(runCtx, parserReader, mirrored, req.Metadata, seq)
291		}()
292	
293		stdoutDone := make(chan struct{})
294		go func() {
295			defer close(stdoutDone)
296			_, _ = io.Copy(parserWriter, stdoutPipe)
297			_ = parserWriter.Close()
298		}()
299	
300		var stderrBuf strings.Builder
301		stderrDone := make(chan struct{})
302		go func() {
303			defer close(stderrDone)
304			_, _ = io.Copy(&stringBuilderWriter{&stderrBuf}, stderrPipe)
305		}()
306	
307		var timedOut bool
308		if req.Timeout > 0 {
309			stop := make(chan struct{})
310			go func() {
311				select {
312				case <-stop:
313				case <-time.After(req.Timeout):
314					timedOut = true
315					cancel()
316				}
317			}()
318			defer close(stop)
319		}
320	
321		cancelDone := make(chan struct{})
322		go func() {
323			defer close(cancelDone)
324			select {
325			case <-ctx.Done():
326				killProcessGroup(cmd)
327			case <-stdoutDone:
328			}
329		}()
330	
331		<-stdoutDone
332		<-stderrDone
333		<-parseDone
334		runErr = cmd.Wait()
335		<-cancelDone
336		stderr = stderrBuf.String()
337	
338		switch {
339		case timedOut:
340			return parseAgg, -1, stderr, context.DeadlineExceeded, "timed_out"
341		case ctx.Err() != nil && errors.Is(ctx.Err(), context.Canceled):
342			return parseAgg, -1, stderr, ctx.Err(), "cancelled"
343		case ctx.Err() != nil && errors.Is(ctx.Err(), context.DeadlineExceeded):
344			return parseAgg, -1, stderr, ctx.Err(), "timed_out"
345		case runErr != nil:
346			ec := -1
347			var exitErr *osexec.ExitError
348			if errors.As(runErr, &exitErr) {
349				ec = exitErr.ExitCode()
350			}
351			return parseAgg, ec, stderr, runErr, "failed"
352		}
353		if parseErr != nil && !errors.Is(parseErr, context.Canceled) {
354			return parseAgg, 0, stderr, parseErr, "failed"
355		}
356		return parseAgg, 0, stderr, nil, "success"
357	}
358	
359	type stringBuilderWriter struct {
360		sb *strings.Builder
361	}
362	
363	func (w *stringBuilderWriter) Write(p []byte) (int, error) {
364		return w.sb.Write(p)
365	}
366	
367	func trimErrorBlob(s string) string {
368		const max = 2048
369		s = strings.TrimSpace(s)
370		if len(s) > max {
371			return s[:max] + "...(truncated)"
372		}
373		return s
374	}
375	
376	func setProcessGroup(cmd *osexec.Cmd) {
377		if cmd.SysProcAttr == nil {
378			cmd.SysProcAttr = &syscall.SysProcAttr{}
379		}
380		setProcessGroupAttr(cmd.SysProcAttr)
381	}
