2	
3	import (
4		"fmt"
5		"os"
6		"os/exec"
7		"regexp"
8		"strconv"
9		"strings"
10		"time"
11	
12		"github.com/easel/fizeau/internal/harnesses"
13	)
14	
15	var ansiPattern = regexp.MustCompile(`\x1b(?:\[[0-9;?]*[a-zA-Z]|[^[])`)
16	
17	func stripANSI(s string) string {
18		return ansiPattern.ReplaceAllString(s, "")
19	}
20	
21	// tmuxRun invokes the tmux binary with the given args and waits for it to
22	// complete. tmuxOutput captures stdout. Both helpers exist to localize the
23	// gosec G204 (subprocess launched with variable) annotation: tmux is a fixed
24	// binary name resolved via PATH, and the variable args are tmux subcommands
25	// plus a service-generated session identifier (`ddx-codex-quota-<pid>`),
26	// never raw external input.
27	func tmuxRun(args ...string) error {
28		// #nosec G204 -- "tmux" is a fixed binary; args are tmux subcommands and a
29		// service-generated session identifier, not external input.
30		return exec.Command("tmux", args...).Run()
31	}
32	
33	func tmuxOutput(args ...string) ([]byte, error) {
34		// #nosec G204 -- "tmux" is a fixed binary; args are tmux subcommands and a
35		// service-generated session identifier, not external input.
36		return exec.Command("tmux", args...).Output()
37	}
38	
39	// ReadCodexQuotaViaTmux starts codex in a detached tmux session, sends /status,
40	// captures the output, and returns parsed quota windows.
41	//
42	// Deprecated: this is a diagnostic-only legacy path. Supported quota probes use
43	// ReadCodexQuotaViaPTY so accepted evidence passes through direct PTY cassettes.
44	func ReadCodexQuotaViaTmux(timeout time.Duration) ([]harnesses.QuotaWindow, error) {
45		if _, err := exec.LookPath("tmux"); err != nil {
46			return nil, fmt.Errorf("tmux not found in PATH: %w", err)
47		}
48		if _, err := exec.LookPath("codex"); err != nil {
49			return nil, fmt.Errorf("codex not found in PATH: %w", err)
50		}
51		if timeout <= 0 {
52			timeout = 30 * time.Second
53		}
54	
55		sessName := fmt.Sprintf("ddx-codex-quota-%d", os.Getpid())
56		if err := tmuxRun("new-session", "-d", "-s", sessName, "-x", "220", "-y", "50", "codex"); err != nil {
57			return nil, fmt.Errorf("start tmux session: %w", err)
58		}
59		defer func() { _ = tmuxRun("kill-session", "-t", sessName) }()
60	
61		// Poll until codex shows its "›" interactive prompt.
62		deadline := time.Now().Add(timeout)
63		ready := false
64		for !ready && time.Now().Before(deadline) {
65			time.Sleep(500 * time.Millisecond)
66			if err := tmuxRun("has-session", "-t", sessName); err != nil {
67				return nil, fmt.Errorf("codex session exited before initialization")
68			}
69			out, err := tmuxOutput("capture-pane", "-t", sessName, "-p")
70			if err == nil {
71				text := stripANSI(string(out))
72				if strings.Contains(text, "›") {
73					ready = true
74				}
75			}
76		}
77		if !ready {
78			return nil, fmt.Errorf("timed out waiting for codex to initialize")
79		}
80	
81		if err := tmuxRun("send-keys", "-t", sessName, "/status", "Enter"); err != nil {
82			return nil, fmt.Errorf("send /status: %w", err)
83		}
84	
85		// Poll until /status output appears ("% left" in output).
86		var captured string
87		for time.Now().Before(deadline) {
88			time.Sleep(500 * time.Millisecond)
89			out, err := tmuxOutput("capture-pane", "-t", sessName, "-p", "-S", "-100")
90			if err == nil {
91				text := stripANSI(string(out))
92				if strings.Contains(text, "% left") {
93					captured = text
94					break
95				}
96			}
97		}
98		if captured == "" {
99			return nil, fmt.Errorf("timed out waiting for /status output")
100		}
101	
102		windows := parseCodexStatusOutput(captured)
103		if len(windows) == 0 {
104			return nil, fmt.Errorf("no quota windows found in /status output")
105		}
106		return windows, nil
107	}
108	
109	var (
110		codexModelLinePattern  = regexp.MustCompile(`\b(gpt-[A-Za-z0-9][A-Za-z0-9._-]*)\b.*?\b(\d{1,3})%\s+(?:left|remaining)\b`)
111		codexWeeklyWarnPattern = regexp.MustCompile(`(?i)(less than\s+)?(\d{1,3})%\s+of your weekly limit\s+(?:left|remaining)`)
112	)
113	
114	// parseCodexStatusOutput parses the text captured from a codex /status pane.
115	// The primary format is: "  gpt-5.4 high · 100% left · /path"
116	// Weekly warning: "Heads up, you have less than 5% of your weekly limit left."
117	func parseCodexStatusOutput(text string) []harnesses.QuotaWindow {
118		text = stripANSI(strings.ReplaceAll(text, "\r\n", "\n"))
119		lines := strings.Split(text, "\n")
120	
121		var windows []harnesses.QuotaWindow
122	
123		// Extract primary window from "model effort · X% left · path" lines.
124		for _, line := range lines {
125			line = strings.TrimSpace(line)
126			if m := codexModelLinePattern.FindStringSubmatch(line); m != nil {
127				pctLeft, _ := strconv.Atoi(m[2])
128				if pctLeft < 0 || pctLeft > 100 {
129					continue
130				}
131				usedPct := 100 - pctLeft
132				windows = append(windows, harnesses.QuotaWindow{
133					Name:          "5h",
134					LimitID:       "codex",
135					WindowMinutes: 300,
136					UsedPercent:   float64(usedPct),
137					State:         harnesses.QuotaStateFromUsedPercent(usedPct),
138				})
139				break
140			}
141		}
142	
143		// Extract weekly warning if present.
144		for _, line := range lines {
145			if m := codexWeeklyWarnPattern.FindStringSubmatch(line); m != nil {
146				pctLeft, _ := strconv.Atoi(m[2])
147				if pctLeft < 0 || pctLeft > 100 {
148					continue
149				}
150				// "less than X%" remaining implies the used percentage is a lower
151				// bound, so state is computed at the next integer.
152				usedFloor := 100 - pctLeft
153				statePercent := usedFloor
154				if strings.TrimSpace(m[1]) != "" {
155					statePercent++
156				}
157				windows = append(windows, harnesses.QuotaWindow{
158					Name:          "7d",
159					LimitID:       "codex",
160					WindowMinutes: 10080,
161					UsedPercent:   float64(usedFloor), // lower bound
162					State:         harnesses.QuotaStateFromUsedPercent(statePercent),
163					ResetsAt:      "",
164				})
165				break
166			}
167		}
168	
169		return windows
170	}
