156	// ReadCached reads a Signal from M1's runtime cache for providerName.
157	// Returns (nil, false) when the entry is absent or cannot be decoded.
158	func ReadCached(cache *discoverycache.Cache, providerName string) (*Signal, bool) {
159		src := CacheSource(providerName)
160		result, err := cache.Read(src)
161		if err != nil || result.Data == nil {
162			return nil, false
163		}
164		var sig Signal
165		if err := json.Unmarshal(result.Data, &sig); err != nil {
166			return nil, false
167		}
168		return &sig, true
169	}
