173	func collectClaudeSignal(sig *Signal) {
174		snap, ok := claudecache.ReadClaudeQuota()
175		if !ok || snap == nil {
176			return // StatusUnknown
177		}
178		if claudecache.ClaudeQuotaSnapshotAge(snap, time.Now()) > claudecache.DefaultClaudeQuotaStaleAfter {
179			return // StatusUnknown; snapshot is stale
180		}
181		if snap.WeeklyRemaining <= 0 || snap.FiveHourRemaining <= 0 {
182			sig.Status = StatusExhausted
183			zero := 0
184			sig.QuotaRemaining = &zero
185			return
186		}
187		sig.Status = StatusAvailable
188		rem := snap.FiveHourRemaining
189		sig.QuotaRemaining = &rem
190	}
191	
192	func collectCodexSignal(sig *Signal) {
193		snap, ok := codexcache.ReadCodexQuota()
194		if !ok || snap == nil {
195			return // StatusUnknown
196		}
197		if codexcache.CodexQuotaSnapshotAge(snap, time.Now()) > codexcache.DefaultCodexQuotaStaleAfter {
198			return // StatusUnknown; snapshot is stale
199		}
200		for _, w := range snap.Windows {
201			if w.UsedPercent >= 95 || w.State == "blocked" {
202				sig.Status = StatusExhausted
203				zero := 0
204				sig.QuotaRemaining = &zero
205				return
206			}
207		}
208		sig.Status = StatusAvailable
209	}
