15	// CodexQuotaSnapshot captures Codex subscription quota windows in a durable
16	// cache so foreground service status calls do not need to spawn a live PTY probe.
17	type CodexQuotaSnapshot struct {
18		CapturedAt time.Time               `json:"captured_at"`
19		Windows    []harnesses.QuotaWindow `json:"windows"`
20		Source     string                  `json:"source"`
21		Account    *harnesses.AccountInfo  `json:"account,omitempty"`
