239	func isSupportedCodexAlias(family string) bool {
240		for _, a := range supportedAliases {
241			if a == family {
242				return true
243			}
244		}
245		return false
246	}
247	
248	// codexQuotaStatusFromSnapshot projects the per-harness snapshot onto
249	// harnesses.QuotaStatus, deriving State and RoutingPreference via the
250	// existing DecideCodexQuotaRouting helper so today's "PreferCodex +
251	// freshness" semantics map cleanly onto CONTRACT-004's RoutingPreference
252	// enum.
253	func codexQuotaStatusFromSnapshot(snap *CodexQuotaSnapshot, now time.Time) harnesses.QuotaStatus {
254		decision := DecideCodexQuotaRouting(snap, now, codexQuotaFreshness)
255		pref, state := mapCodexRoutingPreference(decision)
256		status := harnesses.QuotaStatus{
257			Source:            snap.Source,
258			CapturedAt:        snap.CapturedAt,
259			Fresh:             decision.Fresh,
260			Age:               decision.Age,
261			State:             state,
262			Windows:           append([]harnesses.QuotaWindow(nil), snap.Windows...),
263			RoutingPreference: pref,
264			Reason:            decision.Reason,
265		}
266		if snap.Account != nil {
267			acct := codexAccountSnapshotFromQuotaSnapshot(snap, now)
268			status.Account = &acct
269		}
270		return status
271	}
272	
273	// mapCodexRoutingPreference translates today's PreferCodex+freshness
274	// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
275	// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
276	// stale ⇒ Stale/Blocked ("assume limited"); fresh+PreferCodex ⇒
277	// OK/Available; fresh+!PreferCodex ⇒ Blocked/Blocked.
278	func mapCodexRoutingPreference(d CodexQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
279		if !d.SnapshotPresent {
280			return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
281		}
282		if !d.Fresh {
283			return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
284		}
285		if d.PreferCodex {
286			return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
287		}
288		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
289	}
290	
291	// codexAccountSnapshotFromQuotaSnapshot derives an AccountSnapshot from
292	// the quota cache's embedded Account field. An empty plan-type is
293	// reported as unauthenticated evidence rather than positive
294	// authentication.
295	func codexAccountSnapshotFromQuotaSnapshot(snap *CodexQuotaSnapshot, now time.Time) harnesses.AccountSnapshot {
296		out := harnesses.AccountSnapshot{
297			Source:     "cache",
298			CapturedAt: snap.CapturedAt,
299			Fresh:      IsCodexQuotaFresh(snap, now, codexAccountFreshness),
300		}
301		if snap.Account == nil {
302			return out
303		}
304		plan := strings.TrimSpace(snap.Account.PlanType)
305		out.PlanType = plan
306		out.Email = snap.Account.Email
307		out.OrgName = snap.Account.OrgName
308		if plan == "" {
309			out.Unauthenticated = true
310		} else {
311			out.Authenticated = true
312		}
313		return out
314	}
