18	const codexSessionsRootEnv = "FIZEAU_CODEX_SESSIONS_DIR"
19	
20	const (
21		defaultCodexSessionMaxFiles        = 128
22		defaultCodexSessionMaxBytesPerFile = 8 << 20
23		defaultCodexSessionMaxLineBytes    = 1 << 20
24	)
25	
26	type codexSessionTokenCountConfig struct {
27		root            string
28		now             time.Time
29		staleAfter      time.Duration
30		maxFiles        int
31		maxBytesPerFile int64
32		maxLineBytes    int
33	}
34	
35	// CodexSessionTokenCountOption adjusts bounded session token_count scanning.
36	type CodexSessionTokenCountOption func(*codexSessionTokenCountConfig)
37	
38	func WithCodexSessionTokenCountRoot(root string) CodexSessionTokenCountOption {
39		return func(cfg *codexSessionTokenCountConfig) { cfg.root = root }
40	}
41	
42	func WithCodexSessionTokenCountNow(now time.Time) CodexSessionTokenCountOption {
43		return func(cfg *codexSessionTokenCountConfig) { cfg.now = now }
44	}
45	
46	func WithCodexSessionTokenCountLimits(maxFiles int, maxBytesPerFile int64, maxLineBytes int) CodexSessionTokenCountOption {
47		return func(cfg *codexSessionTokenCountConfig) {
48			cfg.maxFiles = maxFiles
49			cfg.maxBytesPerFile = maxBytesPerFile
50			cfg.maxLineBytes = maxLineBytes
51		}
52	}
53	
54	// CodexSessionsRoot returns the Codex session JSONL root. Tests may override
55	// this with FIZEAU_CODEX_SESSIONS_DIR; normal operation follows CODEX_HOME.
56	func CodexSessionsRoot() (string, error) {
57		if root := strings.TrimSpace(os.Getenv(codexSessionsRootEnv)); root != "" {
58			return root, nil
59		}
60		if home := strings.TrimSpace(os.Getenv("CODEX_HOME")); home != "" {
61			return filepath.Join(home, "sessions"), nil
62		}
63		home, err := os.UserHomeDir()
64		if err != nil {
65			return "", err
66		}
67		return filepath.Join(home, ".codex", "sessions"), nil
68	}
69	
70	// ReadCodexQuotaFromSessionTokenCounts returns the newest fresh quota snapshot
71	// found in Codex token_count events. It never reads session content for
72	// historical analytics and returns false for missing, stale, or malformed
73	// evidence so callers can fall back to the live PTY probe.
74	func ReadCodexQuotaFromSessionTokenCounts(opts ...CodexSessionTokenCountOption) (*CodexQuotaSnapshot, bool) {
75		cfg := defaultCodexSessionTokenCountConfig()
76		for _, opt := range opts {
77			opt(&cfg)
78		}
79		if cfg.root == "" {
80			root, err := CodexSessionsRoot()
81			if err != nil {
82				return nil, false
83			}
84			cfg.root = root
85		}
86		candidates := newestCodexSessionFiles(cfg.root, cfg.maxFiles)
87		for _, candidate := range candidates {
88			snapshot, ok := readCodexTokenCountQuotaFromFile(candidate.path, candidate.modTime, cfg)
89			if !ok {
90				continue
91			}
92			if IsCodexQuotaFresh(snapshot, cfg.now, cfg.staleAfter) {
93				return snapshot, true
94			}
95		}
96		return nil, false
97	}
98	
99	func defaultCodexSessionTokenCountConfig() codexSessionTokenCountConfig {
100		return codexSessionTokenCountConfig{
101			now:             time.Now().UTC(),
102			staleAfter:      DefaultCodexQuotaStaleAfter,
103			maxFiles:        defaultCodexSessionMaxFiles,
104			maxBytesPerFile: defaultCodexSessionMaxBytesPerFile,
105			maxLineBytes:    defaultCodexSessionMaxLineBytes,
106		}
107	}
108	
109	type codexSessionFile struct {
110		path    string
111		modTime time.Time
112	}
113	
114	func newestCodexSessionFiles(root string, maxFiles int) []codexSessionFile {
115		if maxFiles <= 0 {
116			maxFiles = defaultCodexSessionMaxFiles
117		}
118		var files []codexSessionFile
119		_ = filepath.WalkDir(root, func(path string, d os.DirEntry, err error) error {
120			if err != nil {
121				if d != nil && d.IsDir() {
122					return filepath.SkipDir
123				}
124				return nil
125			}
126			if d.Type()&os.ModeSymlink != 0 {
127				if d.IsDir() {
128					return filepath.SkipDir
129				}
130				return nil
131			}
132			if d.IsDir() {
133				return nil
134			}
135			if filepath.Ext(path) != ".jsonl" {
136				return nil
137			}
138			info, err := d.Info()
139			if err != nil || !info.Mode().IsRegular() {
140				return nil
141			}
142			files = append(files, codexSessionFile{path: path, modTime: info.ModTime().UTC()})
143			sortCodexSessionFiles(files)
144			if len(files) > maxFiles {
145				files = files[:maxFiles]
146			}
147			return nil
148		})
149		sortCodexSessionFiles(files)
150		return files
151	}
152	
153	func sortCodexSessionFiles(files []codexSessionFile) {
154		sort.SliceStable(files, func(i, j int) bool {
155			return files[i].modTime.After(files[j].modTime)
156		})
157	}
158	
159	func readCodexTokenCountQuotaFromFile(path string, modTime time.Time, cfg codexSessionTokenCountConfig) (*CodexQuotaSnapshot, bool) {
160		info, err := os.Lstat(path)
161		if err != nil || info.Mode()&os.ModeSymlink != 0 || !info.Mode().IsRegular() {
162			return nil, false
163		}
164		if cfg.maxBytesPerFile <= 0 {
165			cfg.maxBytesPerFile = defaultCodexSessionMaxBytesPerFile
166		}
167		if info.Size() > cfg.maxBytesPerFile {
168			return nil, false
169		}
170		if cfg.maxLineBytes <= 0 {
171			cfg.maxLineBytes = defaultCodexSessionMaxLineBytes
172		}
173	
174		// #nosec G304 -- Codex session paths are intentionally discovered under
175		// CODEX_HOME; scanning is size-bounded and content is not logged.
176		f, err := os.Open(path)
177		if err != nil {
178			return nil, false
179		}
180		defer f.Close()
181	
182		scanner := bufio.NewScanner(io.LimitReader(f, cfg.maxBytesPerFile))
183		scanner.Buffer(make([]byte, 0, min(cfg.maxLineBytes, 64*1024)), cfg.maxLineBytes)
184		var newest *CodexQuotaSnapshot
185		for scanner.Scan() {
186			snapshot, ok := parseCodexTokenCountQuotaLine(scanner.Bytes(), modTime)
187			if !ok {
188				continue
189			}
190			if newest == nil || snapshot.CapturedAt.After(newest.CapturedAt) {
191				newest = snapshot
192			}
193		}
194		if newest == nil {
195			return nil, false
196		}
197		return newest, true
198	}
199	
200	type codexTokenCountLine struct {
201		Type      string `json:"type"`
202		Timestamp string `json:"timestamp"`
203		Payload   struct {
204			Type string `json:"type"`
205			Info struct {
206				RateLimits json.RawMessage `json:"rate_limits"`
207			} `json:"info"`
208			RateLimits json.RawMessage `json:"rate_limits"`
209		} `json:"payload"`
210	}
211	
212	func parseCodexTokenCountQuotaLine(raw []byte, fileModTime time.Time) (*CodexQuotaSnapshot, bool) {
213		var ev codexTokenCountLine
214		if err := json.Unmarshal(raw, &ev); err != nil {
215			return nil, false
216		}
217		if ev.Type != "event_msg" || ev.Payload.Type != "token_count" {
218			return nil, false
219		}
220		rateLimits := codexTokenCountRateLimitsRaw(ev.Payload.RateLimits, ev.Payload.Info.RateLimits)
221		if len(rateLimits) == 0 {
222			return nil, false
223		}
224		snapshot, ok := CodexQuotaSnapshotFromTokenCountRateLimits(ev.Timestamp, fileModTime, rateLimits)
225		if ok {
226			snapshot.Source = "codex_session_token_count"
227		}
228		return snapshot, ok
229	}
230	
231	// CodexQuotaSnapshotFromTokenCountRateLimits builds a quota snapshot from a
232	// token_count.rate_limits payload. fallbackCapturedAt must be evidence time:
233	// session readers pass file mtime, while live DDx-owned streams may pass now.
234	func CodexQuotaSnapshotFromTokenCountRateLimits(timestamp string, fallbackCapturedAt time.Time, rateLimits json.RawMessage) (*CodexQuotaSnapshot, bool) {
235		capturedAt := codexTokenCountCapturedAt(timestamp, fallbackCapturedAt)
236		windows, account, ok := codexQuotaSnapshotFromTokenCountRateLimits(rateLimits)
237		if !ok {
238			return nil, false
239		}
240		return &CodexQuotaSnapshot{
241			CapturedAt: capturedAt,
242			Windows:    windows,
243			Source:     "codex_token_count",
244			Account:    account,
245		}, true
246	}
247	
248	func codexTokenCountCapturedAt(timestamp string, fileModTime time.Time) time.Time {
249		timestamp = strings.TrimSpace(timestamp)
250		if timestamp != "" {
251			if parsed, err := time.Parse(time.RFC3339Nano, timestamp); err == nil {
252				return parsed.UTC()
253			}
254		}
255		return fileModTime.UTC()
256	}
257	
258	func codexQuotaSnapshotFromTokenCountRateLimits(raw json.RawMessage) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, bool) {
259		var obj map[string]json.RawMessage
260		if err := json.Unmarshal(raw, &obj); err != nil {
261			return nil, nil, false
262		}
263		var windows []harnesses.QuotaWindow
264		keys := make([]string, 0, len(obj))
265		for key := range obj {
266			keys = append(keys, key)
267		}
268		sort.Strings(keys)
269		for _, key := range keys {
270			window, ok := codexQuotaWindowFromRaw(obj[key])
271			if ok {
272				windows = append(windows, window)
273			}
274		}
275		if len(windows) == 0 {
276			return nil, nil, false
277		}
278		var account *harnesses.AccountInfo
279		if plan := stringFromRaw(obj["plan_type"]); plan != "" {
280			account = &harnesses.AccountInfo{PlanType: normalizeCodexPlanType(plan)}
281		}
282		return windows, account, true
283	}
284	
285	func codexQuotaWindowFromRaw(raw json.RawMessage) (harnesses.QuotaWindow, bool) {
286		var obj map[string]json.RawMessage
287		if err := json.Unmarshal(raw, &obj); err != nil || obj == nil {
288			return harnesses.QuotaWindow{}, false
289		}
290		windowMinutes, ok := intFromRaw(obj["window_minutes"])
291		if !ok || windowMinutes <= 0 {
292			return harnesses.QuotaWindow{}, false
293		}
294		usedPercent, ok := floatFromRaw(obj["used_percent"])
295		if !ok {
296			return harnesses.QuotaWindow{}, false
297		}
298		window := harnesses.QuotaWindow{
299			Name:          codexQuotaWindowName(windowMinutes),
300			LimitID:       stringFromRaw(obj["limit_id"]),
301			LimitName:     stringFromRaw(obj["limit_name"]),
302			WindowMinutes: windowMinutes,
303			UsedPercent:   usedPercent,
304			State:         harnesses.QuotaStateFromUsedPercent(int(usedPercent)),
305		}
306		if resetsAt, ok := int64FromRaw(obj["resets_at"]); ok && resetsAt > 0 {
307			window.ResetsAtUnix = resetsAt
308			window.ResetsAt = time.Unix(resetsAt, 0).UTC().Format(time.RFC3339)
309		}
310		return window, true
311	}
312	
313	func codexQuotaWindowName(minutes int) string {
314		if minutes%(24*60) == 0 {
315			return fmt.Sprintf("%dd", minutes/(24*60))
316		}
317		if minutes%60 == 0 {
318			return fmt.Sprintf("%dh", minutes/60)
319		}
320		return fmt.Sprintf("%dm", minutes)
321	}
322	
323	func stringFromRaw(raw json.RawMessage) string {
324		if len(raw) == 0 || string(raw) == "null" {
325			return ""
326		}
327		var s string
328		if err := json.Unmarshal(raw, &s); err == nil {
329			return strings.TrimSpace(s)
330		}
331		return ""
332	}
333	
334	func intFromRaw(raw json.RawMessage) (int, bool) {
335		n, ok := int64FromRaw(raw)
336		return int(n), ok
337	}
338	
339	func int64FromRaw(raw json.RawMessage) (int64, bool) {
340		if len(raw) == 0 || string(raw) == "null" {
341			return 0, false
342		}
343		var n int64
344		if err := json.Unmarshal(raw, &n); err == nil {
345			return n, true
346		}
347		var f float64
348		if err := json.Unmarshal(raw, &f); err == nil {
349			return int64(f), true
350		}
351		var s string
352		if err := json.Unmarshal(raw, &s); err == nil {
353			parsed, err := strconv.ParseInt(strings.TrimSpace(s), 10, 64)
354			return parsed, err == nil
355		}
356		return 0, false
357	}
358	
359	func floatFromRaw(raw json.RawMessage) (float64, bool) {
360		if len(raw) == 0 || string(raw) == "null" {
361			return 0, false
362		}
363		var f float64
364		if err := json.Unmarshal(raw, &f); err == nil {
365			return f, true
366		}
367		var s string
368		if err := json.Unmarshal(raw, &s); err == nil {
369			parsed, err := strconv.ParseFloat(strings.TrimSpace(s), 64)
370			return parsed, err == nil
371		}
372		return 0, false
373	}
