13	
14	const codexAuthPathEnv = "FIZEAU_CODEX_AUTH"
15	
16	const codexAuthNamespace = "https://api.openai.com/auth"
17	
18	// CodexAuthPath returns the local Codex auth file used for account metadata.
19	func CodexAuthPath() (string, error) {
20		if path := os.Getenv(codexAuthPathEnv); path != "" {
21			return path, nil
22		}
23		if home := os.Getenv("CODEX_HOME"); home != "" {
24			return filepath.Join(home, "auth.json"), nil
25		}
26		home, err := os.UserHomeDir()
27		if err != nil {
28			return "", err
29		}
30		return filepath.Join(home, ".codex", "auth.json"), nil
31	}
32	
33	// ReadCodexAccount extracts non-secret account metadata from Codex auth state.
34	func ReadCodexAccount() (*harnesses.AccountInfo, bool) {
35		path, err := CodexAuthPath()
36		if err != nil {
37			return nil, false
38		}
39		return ReadCodexAccountFrom(path)
40	}
41	
42	// ReadCodexAccountFrom reads auth.json and extracts email, plan, and org info.
43	func ReadCodexAccountFrom(path string) (*harnesses.AccountInfo, bool) {
44		data, err := safefs.ReadFile(path)
45		if err != nil {
46			return nil, false
47		}
48		var auth struct {
49			Tokens struct {
50				IDToken string `json:"id_token"`
51			} `json:"tokens"`
52			OpenAIAPIKey string `json:"OPENAI_API_KEY"`
53		}
54		if err := json.Unmarshal(data, &auth); err != nil {
55			return nil, false
56		}
57		if auth.Tokens.IDToken != "" {
58			if account, ok := codexAccountFromIDToken(auth.Tokens.IDToken); ok {
59				return account, true
60			}
61		}
62		if auth.OpenAIAPIKey != "" {
63			return &harnesses.AccountInfo{PlanType: "OpenAI API key"}, true
64		}
65		return nil, false
66	}
67	
68	func codexAccountFromIDToken(token string) (*harnesses.AccountInfo, bool) {
69		parts := strings.Split(token, ".")
70		if len(parts) < 2 {
71			return nil, false
72		}
73		payload, err := base64.RawURLEncoding.DecodeString(parts[1])
74		if err != nil {
75			payload, err = base64.URLEncoding.DecodeString(parts[1])
76			if err != nil {
77				return nil, false
78			}
79		}
80		var claims map[string]any
81		if err := json.Unmarshal(payload, &claims); err != nil {
82			return nil, false
83		}
84		account := &harnesses.AccountInfo{
85			Email:    stringClaim(claims, "email"),
86			PlanType: normalizeCodexPlanType(nestedStringClaim(claims, codexAuthNamespace, "chatgpt_plan_type")),
87			OrgName:  defaultCodexOrgName(claims),
88		}
89		if account.Email == "" && account.PlanType == "" && account.OrgName == "" {
90			return nil, false
91		}
92		return account, true
93	}
94	
95	func stringClaim(claims map[string]any, key string) string {
96		value, _ := claims[key].(string)
97		return strings.TrimSpace(value)
98	}
99	
100	func nestedStringClaim(claims map[string]any, namespace, key string) string {
101		nested, _ := claims[namespace].(map[string]any)
102		if nested == nil {
103			return ""
104		}
105		return stringClaim(nested, key)
106	}
107	
108	func defaultCodexOrgName(claims map[string]any) string {
109		nested, _ := claims[codexAuthNamespace].(map[string]any)
110		if nested == nil {
111			return ""
112		}
113		orgs, _ := nested["organizations"].([]any)
114		var first string
115		for _, raw := range orgs {
116			org, _ := raw.(map[string]any)
117			if org == nil {
118				continue
119			}
120			title, _ := org["title"].(string)
121			title = strings.TrimSpace(title)
122			if title == "" {
123				continue
124			}
125			if first == "" {
126				first = title
127			}
128			if isDefault, _ := org["is_default"].(bool); isDefault {
129				return title
130			}
131		}
132		return first
133	}
134	
135	func normalizeCodexPlanType(plan string) string {
136		plan = strings.TrimSpace(plan)
137		if plan == "" {
138			return ""
139		}
140		lower := strings.ToLower(strings.ReplaceAll(plan, "_", " "))
141		switch {
142		case strings.Contains(lower, "enterprise"):
143			return "ChatGPT Enterprise"
144		case strings.Contains(lower, "team"):
145			return "ChatGPT Team"
146		case strings.Contains(lower, "max"):
147			return "ChatGPT Max"
148		case strings.Contains(lower, "pro"):
149			return "ChatGPT Pro"
150		case strings.Contains(lower, "plus"):
151			return "ChatGPT Plus"
152		case strings.Contains(lower, "free"):
153			return "ChatGPT Free"
154		}
155		if strings.HasPrefix(plan, "ChatGPT ") {
156			return plan
157		}
158		return "ChatGPT " + plan
159	}
160	
161	func codexAccountSupportsAutoRouting(account *harnesses.AccountInfo) bool {
162		if account == nil {
163			return false
164		}
165		switch account.PlanType {
166		case "ChatGPT Enterprise", "ChatGPT Team", "ChatGPT Max", "ChatGPT Pro", "ChatGPT Plus":
167			return true
168		default:
169			return false
170		}
171	}
