15	
16	const CodexModelDiscoveryFreshnessWindow = 24 * time.Hour
17	
18	var codexModelPattern = regexp.MustCompile(`\bgpt-[A-Za-z0-9][A-Za-z0-9._-]*\b`)
19	
20	func DefaultCodexModelDiscovery() harnesses.ModelDiscoverySnapshot {
21		return harnesses.ModelDiscoverySnapshot{
22			CapturedAt:      time.Now().UTC(),
23			Models:          []string{"gpt", "gpt-5", "gpt-5.5", "gpt-5.4", "gpt-5.4-mini"},
24			ReasoningLevels: []string{"low", "medium", "high", "xhigh", "max"},
25			Source:          "compatibility-table:codex-cli",
26			FreshnessWindow: CodexModelDiscoveryFreshnessWindow.String(),
27			Detail:          "codex CLI exposes exact model pins with -m/--model; model IDs are refreshed by authenticated PTY record tests",
28		}
29	}
30	
31	func ReadCodexModelDiscoveryViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (harnesses.ModelDiscoverySnapshot, error) {
32		cfg := quotaPTYOptions{binary: "codex", args: []string{"--no-alt-screen"}}
33		for _, opt := range opts {
34			if opt != nil {
35				opt(&cfg)
36			}
37		}
38		var snapshot harnesses.ModelDiscoverySnapshot
39		_, err := ptyquota.Run(context.Background(), ptyquota.Config{
40			HarnessName:        "codex",
41			Binary:             cfg.binary,
42			Args:               cfg.args,
43			Workdir:            cfg.workdir,
44			Env:                cfg.env,
45			Command:            "/model\r",
46			ReadyMarkers:       []string{"›", "> "},
47			DoneWhen:           codexModelDiscoveryComplete,
48			ResetBeforeCommand: true,
49			Timeout:            timeout,
50			Size:               session.Size{Rows: 50, Cols: 220},
51			CassetteDir:        cfg.cassetteDir,
52			Discovery: func(text string) (cassette.DiscoveryRecord, error) {
53				snapshot = codexDiscoveryFromText(text, "pty")
54				if len(snapshot.Models) == 0 {
55					return cassette.DiscoveryRecord{}, fmt.Errorf("no models found in codex /model output")
56				}
57				return discoveryRecord(snapshot), nil
58			},
59		})
60		if err != nil {
61			return harnesses.ModelDiscoverySnapshot{}, err
62		}
63		if len(snapshot.Models) == 0 {
64			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("no models found in codex /model output")
65		}
66		return snapshot, nil
67	}
