69	func ReadCodexModelDiscoveryFromCassette(dir string) (harnesses.ModelDiscoverySnapshot, error) {
70		reader, err := cassette.Open(dir)
71		if err != nil {
72			return harnesses.ModelDiscoverySnapshot{}, err
73		}
74		if rec := reader.Discovery(); rec != nil && len(rec.Models) > 0 {
75			return snapshotFromDiscoveryRecord(*rec), nil
76		}
77		text := reader.Final().FinalText
78		if text == "" {
79			frames := reader.Frames()
80			if len(frames) > 0 {
81				text = strings.Join(frames[len(frames)-1].Text, "\n")
82			}
83		}
84		snapshot := codexDiscoveryFromText(text, "cassette")
85		if len(snapshot.Models) == 0 {
86			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("no models found in codex model cassette")
87		}
88		return snapshot, nil
89	}
