91	func codexModelDiscoveryComplete(text string) bool {
92		return len(parseCodexModels(text)) > 0
93	}
94	
95	func codexDiscoveryFromText(text, source string) harnesses.ModelDiscoverySnapshot {
96		snapshot := DefaultCodexModelDiscovery()
97		if source != "" {
98			snapshot.Source = source
99		}
100		if models := parseCodexModels(text); len(models) > 0 {
101			snapshot.Models = models
102		}
103		return snapshot
104	}
105	
106	func parseCodexModels(text string) []string {
107		text = stripANSI(strings.ReplaceAll(text, "\r\n", "\n"))
108		return uniqueMatches(codexModelPattern.FindAllString(text, -1))
109	}
110	
111	func ResolveCodexModelAlias(model string, snapshot harnesses.ModelDiscoverySnapshot) string {
112		model = strings.ToLower(strings.TrimSpace(model))
113		if model == "" {
114			return model
115		}
116		switch {
117		case model == "gpt":
118			if resolved := latestCodexModel("", snapshot.Models); resolved != "" {
119				return resolved
120			}
121		case regexp.MustCompile(`^gpt-[0-9]+$`).MatchString(model):
122			if resolved := latestCodexModel(strings.TrimPrefix(model, "gpt-"), snapshot.Models); resolved != "" {
123				return resolved
124			}
125		}
126		return model
127	}
128	
129	func latestCodexModel(major string, models []string) string {
130		best := ""
131		var bestParts []int
132		bestHasSuffix := true
133		for _, model := range models {
134			candidate := strings.ToLower(strings.TrimSpace(model))
135			parts, hasSuffix, ok := parseCodexVersion(candidate)
136			if !ok {
137				continue
138			}
139			if major != "" && (len(parts) == 0 || fmt.Sprint(parts[0]) != major) {
140				continue
141			}
142			if best == "" || compareCodexVersion(parts, hasSuffix, bestParts, bestHasSuffix) > 0 {
143				best = candidate
144				bestParts = parts
145				bestHasSuffix = hasSuffix
146			}
147		}
148		return best
149	}
150	
151	func parseCodexVersion(model string) ([]int, bool, bool) {
152		if !strings.HasPrefix(model, "gpt-") {
153			return nil, false, false
154		}
155		rest := strings.TrimPrefix(model, "gpt-")
156		raw := strings.FieldsFunc(rest, func(r rune) bool { return r == '.' || r == '-' })
157		if len(raw) == 0 {
158			return nil, false, false
159		}
160		parts := make([]int, 0, len(raw))
161		hasSuffix := false
162		for _, part := range raw {
163			if part == "" {
164				return nil, false, false
165			}
166			n := 0
167			for _, r := range part {
168				if r < '0' || r > '9' {
169					hasSuffix = true
170					return parts, hasSuffix, len(parts) > 0
171				}
172				n = n*10 + int(r-'0')
173			}
174			parts = append(parts, n)
175		}
176		return parts, hasSuffix, true
177	}
178	
179	func compareCodexVersion(a []int, aHasSuffix bool, b []int, bHasSuffix bool) int {
180		n := len(a)
181		if len(b) > n {
182			n = len(b)
183		}
184		for i := 0; i < n; i++ {
185			av, bv := 0, 0
186			if i < len(a) {
187				av = a[i]
188			}
189			if i < len(b) {
190				bv = b[i]
191			}
192			if av > bv {
193				return 1
194			}
195			if av < bv {
196				return -1
197			}
198		}
199		if aHasSuffix == bHasSuffix {
200			return 0
201		}
202		if !aHasSuffix {
203			return 1
204		}
205		return -1
206	}
207	
208	func discoveryRecord(snapshot harnesses.ModelDiscoverySnapshot) cassette.DiscoveryRecord {
209		return cassette.DiscoveryRecord{
210			Source:            snapshot.Source,
211			Status:            string(ptyquota.StatusOK),
212			Models:            append([]string(nil), snapshot.Models...),
213			ReasoningLevels:   append([]string(nil), snapshot.ReasoningLevels...),
214			CapturedAt:        snapshot.CapturedAt.UTC().Format(time.RFC3339),
215			FreshnessWindow:   snapshot.FreshnessWindow,
216			StalenessBehavior: "stale model discovery evidence requires authenticated PTY refresh before capability promotion",
217			Metadata:          map[string]any{"detail": snapshot.Detail},
218		}
219	}
220	
221	func snapshotFromDiscoveryRecord(rec cassette.DiscoveryRecord) harnesses.ModelDiscoverySnapshot {
222		capturedAt, _ := time.Parse(time.RFC3339, rec.CapturedAt)
223		detail, _ := rec.Metadata["detail"].(string)
224		return harnesses.ModelDiscoverySnapshot{
225			CapturedAt:      capturedAt,
226			Models:          append([]string(nil), rec.Models...),
227			ReasoningLevels: append([]string(nil), rec.ReasoningLevels...),
228			Source:          rec.Source,
229			FreshnessWindow: rec.FreshnessWindow,
230			Detail:          detail,
231		}
232	}
233	
234	func uniqueMatches(values []string) []string {
235		seen := map[string]bool{}
236		out := make([]string, 0, len(values))
237		for _, value := range values {
238			value = strings.TrimSpace(value)
239			if value == "" || seen[value] {
240				continue
241			}
242			seen[value] = true
243			out = append(out, value)
244		}
245		return out
246	}
