50	func ReadCodexQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, error) {
51		windows, _, err := captureCodexQuotaViaPTY(context.Background(), timeout, opts...)
