55	func RefreshCodexQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (CodexQuotaSnapshot, error) {
56		windows, _, err := captureCodexQuotaViaPTY(context.Background(), timeout, opts...)
57		if err != nil {
58			return CodexQuotaSnapshot{}, err
59		}
60		return CodexQuotaSnapshot{
