68	func ReadCodexQuotaFromCassette(dir string) ([]harnesses.QuotaWindow, error) {
69		reader, err := cassette.Open(dir)
70		if err != nil {
71			return nil, err
72		}
73		text := reader.Final().FinalText
74		if text == "" {
75			frames := reader.Frames()
76			if len(frames) > 0 {
77				text = strings.Join(frames[len(frames)-1].Text, "\n")
78			}
79		}
80		windows := parseCodexStatusOutput(text)
81		if len(windows) == 0 {
82			return nil, fmt.Errorf("no quota windows found in codex quota cassette")
83		}
84		return windows, nil
85	}
86	
87	func captureCodexQuotaViaPTY(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, ptyquota.Result, error) {
88		cfg := quotaPTYOptions{binary: "codex", args: []string{"--no-alt-screen"}}
89		for _, opt := range opts {
90			if opt != nil {
91				opt(&cfg)
92			}
93		}
94		var windows []harnesses.QuotaWindow
95		result, err := ptyquota.Run(ctx, ptyquota.Config{
96			HarnessName:        "codex",
97			Binary:             cfg.binary,
98			Args:               cfg.args,
99			Workdir:            cfg.workdir,
100			Env:                cfg.env,
101			Command:            "/status\r",
102			ReadyMarkers:       []string{"›", "> "},
103			DoneAnyMarkers:     []string{"›", "> "},
104			DoneWhen:           codexQuotaOutputComplete,
105			ResetBeforeCommand: true,
106			Timeout:            timeout,
107			Size:               session.Size{Rows: 50, Cols: 220},
108			CassetteDir:        cfg.cassetteDir,
109			Quota: func(text string) (cassette.QuotaRecord, error) {
110				windows = parseCodexStatusOutput(text)
111				if len(windows) == 0 {
112					return cassette.QuotaRecord{}, fmt.Errorf("no quota windows found in codex /status output")
113				}
114				return quotaRecord(windows), nil
115			},
116		})
117		if err != nil {
118			return nil, result, err
119		}
120		if len(windows) == 0 {
121			windows = parseCodexStatusOutput(result.Text)
122		}
123		if len(windows) == 0 {
124			return nil, result, fmt.Errorf("no quota windows found in codex /status output")
125		}
126		return windows, result, nil
127	}
128	
129	func readCodexAccountOrNil() *harnesses.AccountInfo {
130		account, _ := ReadCodexAccount()
131		return account
132	}
133	
134	func codexQuotaOutputComplete(text string) bool {
135		return strings.Contains(text, "/status") && len(parseCodexStatusOutput(text)) > 0
136	}
137	
138	func quotaRecord(windows []harnesses.QuotaWindow) cassette.QuotaRecord {
139		records := make([]map[string]any, 0, len(windows))
140		for _, window := range windows {
141			records = append(records, map[string]any{
142				"name":           window.Name,
143				"limit_id":       window.LimitID,
144				"window_minutes": window.WindowMinutes,
145				"used_percent":   window.UsedPercent,
146				"resets_at":      window.ResetsAt,
147				"state":          window.State,
148			})
149		}
150		metadata := map[string]any{}
151		var accountClass string
152		if account, ok := ReadCodexAccount(); ok {
153			metadata["plan_type"] = account.PlanType
154			metadata["org_name"] = account.OrgName
155			accountClass = account.PlanType
156		}
157		return cassette.QuotaRecord{
158			Source:            "pty",
159			Status:            string(ptyquota.StatusOK),
160			CapturedAt:        time.Now().UTC().Format(time.RFC3339),
161			FreshnessWindow:   DefaultCodexQuotaStaleAfter.String(),
162			StalenessBehavior: "stale quota evidence keeps Codex out of automatic routing and is treated as limited",
163			AccountClass:      accountClass,
164			Windows:           records,
165			Metadata:          metadata,
166		}
167	}
