13	func TestCodexQuotaSnapshotRoundTrip(t *testing.T) {
14		t.Setenv(codexAuthPathEnv, filepath.Join(t.TempDir(), "missing-auth.json"))
15		path := filepath.Join(t.TempDir(), "codex-quota.json")
16		original := CodexQuotaSnapshot{
17			CapturedAt: time.Now().UTC().Add(-time.Minute).Truncate(time.Second),
18			Source:     "pty",
19			Account:    &harnesses.AccountInfo{Email: "dev@example.com", PlanType: "ChatGPT Pro", OrgName: "agent"},
20			Windows: []harnesses.QuotaWindow{
21				{Name: "5h", LimitID: "codex", WindowMinutes: 300, UsedPercent: 25, State: "ok"},
22			},
23		}
24		if err := WriteCodexQuota(path, original); err != nil {
25			t.Fatalf("WriteCodexQuota: %v", err)
26		}
27		loaded, ok := ReadCodexQuotaFrom(path)
28		if !ok {
29			t.Fatal("ReadCodexQuotaFrom returned ok=false")
30		}
31		if !loaded.CapturedAt.Equal(original.CapturedAt) {
32			t.Fatalf("CapturedAt: got %v, want %v", loaded.CapturedAt, original.CapturedAt)
33		}
34		if loaded.Source != "pty" {
35			t.Fatalf("Source: got %q, want pty", loaded.Source)
36		}
37		if loaded.Account == nil || loaded.Account.PlanType != "ChatGPT Pro" || loaded.Account.Email != "dev@example.com" {
38			t.Fatalf("Account: got %#v", loaded.Account)
39		}
40		if len(loaded.Windows) != 1 || loaded.Windows[0].UsedPercent != 25 {
41			t.Fatalf("Windows: got %#v", loaded.Windows)
42		}
43	}
