152	func writeSessionJSONL(t *testing.T, path string, mtime time.Time, lines ...string) {
153		t.Helper()
154		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
155			t.Fatal(err)
156		}
157		content := ""
158		for _, line := range lines {
159			content += line + "\n"
160		}
161		if err := os.WriteFile(path, []byte(content), 0o600); err != nil {
162			t.Fatal(err)
163		}
164		if err := os.Chtimes(path, mtime, mtime); err != nil {
165			t.Fatal(err)
166		}
167	}
