169	func tokenCountLine(timestamp string, primaryUsed string) string {
170		return `{"type":"event_msg","timestamp":"` + timestamp + `","payload":{"type":"token_count","info":{"rate_limits":{"plan_type":"pro","primary":{` + primaryUsed + `,"window_minutes":300,"resets_at":1776840333,"limit_id":"codex","limit_name":"primary credits"},"secondary":{"used_percent":2,"window_minutes":10080,"resets_at":"1777400415","limit_id":"codex-weekly"}}}}}`
171	}
172	
173	func mustTime(t *testing.T, value string) time.Time {
174		t.Helper()
175		parsed, err := time.Parse(time.RFC3339Nano, value)
176		if err != nil {
177			t.Fatal(err)
178		}
179		return parsed.UTC()
180	}
