31	type Store struct {
32		mu        sync.RWMutex
33		latencies map[string]*LatencyWindow
34		headers   *headerStore
35	}
36	
37	// CollectInput describes the provider identity needed to assemble a runtime
38	// signal. Type controls the collection path; BaseURL is used by local
39	// providers for the live /v1/models check.
40	type CollectInput struct {
41		Type    string
42		BaseURL string
43	}
44	
45	// NewStore creates an empty Store ready for use.
46	func NewStore() *Store {
47		return &Store{
48			latencies: make(map[string]*LatencyWindow),
49			headers:   newHeaderStore(),
50		}
51	}
52	
53	// DefaultStore is the process-singleton Store used by the package-level
54	// RecordResponse and Collect functions.
55	var DefaultStore = NewStore()
56	
57	// RecordResponse records an HTTP response observation for a provider using the
58	// DefaultStore. providerType controls which header parser is applied
59	// ("openrouter", "anthropic", or any other value for the OpenAI parser).
60	func RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
61		DefaultStore.RecordResponse(provider, h, latency, providerType)
62	}
63	
64	// RecordResponse records an HTTP response observation. It updates both the
65	// latency window and the header signal store for the named provider.
66	func (s *Store) RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
67		win := s.latencyWindow(provider)
68		win.Record(latency)
69	
70		if h != nil {
71			now := time.Now()
72			var sig quotaheaders.Signal
73			switch providerType {
74			case "openrouter":
75				sig = quotaheaders.ParseOpenRouter(h, now)
76			case "anthropic":
77				sig = quotaheaders.ParseAnthropic(h, now)
78			default:
79				sig = quotaheaders.ParseOpenAI(h, now)
80			}
81			s.headers.record(provider, sig)
82		}
83	}
84	
85	// Collect assembles a runtime Signal for the named provider using
86	// DefaultStore.
87	func Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
88		return DefaultStore.Collect(ctx, providerName, cfg)
89	}
90	
91	// Collect assembles a runtime Signal for providerName. The cfg.Type field
92	// controls which collection path is used:
93	//
94	//   - "claude"       → existing internal/harnesses/claude/quota_cache.go
95	//   - "codex"        → existing internal/harnesses/codex/quota_cache.go
96	//   - "gemini"       → existing internal/harnesses/gemini/quota_cache.go
97	//   - "openrouter"   → most recently recorded rate-limit headers (OpenRouter parser)
98	//   - "openai", "anthropic", and unknown HTTP types → rate-limit headers
99	//   - local types    → HTTP GET /v1/models alive check (no quota concept)
100	func (s *Store) Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
101		sig := Signal{
102			Provider:   providerName,
103			Status:     StatusUnknown,
104			RecordedAt: time.Now().UTC(),
105		}
106	
107		s.mu.RLock()
108		win := s.latencies[providerName]
109		s.mu.RUnlock()
110		if win != nil {
111			sig.RecentP50Latency = win.P50()
112		}
113	
114		providerType := cfg.Type
115	
116		switch providerType {
117		case "claude":
118			collectClaudeSignal(&sig)
119		case "codex":
120			collectCodexSignal(&sig)
121		case "gemini":
122			collectGeminiSignal(&sig)
123		case "ds4", "llama-server", "omlx", "lmstudio", "lucebox", "vllm", "rapid-mlx", "ollama":
124			collectLocalSignal(ctx, cfg.BaseURL, &sig)
125		default:
126			s.collectHeaderSignal(providerName, &sig)
127		}
128	
129		return sig, nil
130	}
131	
132	// CacheSource returns the discoverycache.Source descriptor for a provider's
133	// runtime signal. The file path resolves to runtime/<provider>.json.
134	func CacheSource(providerName string) discoverycache.Source {
135		return discoverycache.Source{
136			Tier:            "runtime",
137			Name:            providerName,
138			TTL:             RuntimeTTL,
139			RefreshDeadline: RuntimeRefreshDeadline,
140		}
141	}
142	
143	// Write serializes sig and stores it in M1's runtime cache tier. The cache
144	// file lands at <cache.Root>/runtime/<sig.Provider>.json.
145	func Write(cache *discoverycache.Cache, sig Signal) error {
146		data, err := json.Marshal(sig)
147		if err != nil {
148			return err
149		}
150		src := CacheSource(sig.Provider)
151		return cache.Refresh(src, func(_ context.Context) ([]byte, error) {
152			return data, nil
153		})
154	}
155	
156	// ReadCached reads a Signal from M1's runtime cache for providerName.
157	// Returns (nil, false) when the entry is absent or cannot be decoded.
158	func ReadCached(cache *discoverycache.Cache, providerName string) (*Signal, bool) {
159		src := CacheSource(providerName)
160		result, err := cache.Read(src)
161		if err != nil || result.Data == nil {
162			return nil, false
163		}
164		var sig Signal
165		if err := json.Unmarshal(result.Data, &sig); err != nil {
166			return nil, false
167		}
168		return &sig, true
169	}
170	
171	// ---- per-provider-type collectors -------------------------------------------
172	
173	func collectClaudeSignal(sig *Signal) {
174		snap, ok := claudecache.ReadClaudeQuota()
175		if !ok || snap == nil {
176			return // StatusUnknown
177		}
178		if claudecache.ClaudeQuotaSnapshotAge(snap, time.Now()) > claudecache.DefaultClaudeQuotaStaleAfter {
179			return // StatusUnknown; snapshot is stale
180		}
181		if snap.WeeklyRemaining <= 0 || snap.FiveHourRemaining <= 0 {
182			sig.Status = StatusExhausted
183			zero := 0
184			sig.QuotaRemaining = &zero
185			return
186		}
187		sig.Status = StatusAvailable
188		rem := snap.FiveHourRemaining
189		sig.QuotaRemaining = &rem
190	}
191	
192	func collectCodexSignal(sig *Signal) {
193		snap, ok := codexcache.ReadCodexQuota()
194		if !ok || snap == nil {
195			return // StatusUnknown
196		}
197		if codexcache.CodexQuotaSnapshotAge(snap, time.Now()) > codexcache.DefaultCodexQuotaStaleAfter {
198			return // StatusUnknown; snapshot is stale
199		}
200		for _, w := range snap.Windows {
201			if w.UsedPercent >= 95 || w.State == "blocked" {
202				sig.Status = StatusExhausted
203				zero := 0
204				sig.QuotaRemaining = &zero
205				return
206			}
207		}
208		sig.Status = StatusAvailable
209	}
210	
211	func collectGeminiSignal(sig *Signal) {
212		r := &geminiharness.Runner{}
213		status, err := r.QuotaStatus(context.Background(), time.Now())
214		if err != nil {
215			return
216		}
217		switch status.State {
218		case harnesses.QuotaOK:
219			sig.Status = StatusAvailable
220		case harnesses.QuotaBlocked:
221			sig.Status = StatusExhausted
222			zero := 0
223			sig.QuotaRemaining = &zero
224			// QuotaUnavailable and QuotaStale both leave Status as StatusUnknown
225		}
226	}
227	
228	// collectHeaderSignal reads the most recently recorded rate-limit header signal
229	// for the provider and populates sig accordingly.
230	func (s *Store) collectHeaderSignal(providerName string, sig *Signal) {
231		hSig, ok := s.headers.get(providerName)
232		if !ok {
233			return // StatusUnknown; no headers observed yet
234		}
235		exhausted, retryAfter := hSig.IsExhausted(time.Now())
236		if exhausted {
237			sig.Status = StatusExhausted
238			zero := 0
239			sig.QuotaRemaining = &zero
240			if !retryAfter.IsZero() {
241				t := retryAfter
242				sig.QuotaResetAt = &t
243			}
244			return
245		}
246		sig.Status = StatusAvailable
247		switch {
248		case hSig.RemainingRequests >= 0:
249			rem := int(hSig.RemainingRequests)
250			sig.QuotaRemaining = &rem
251		case hSig.RemainingTokens >= 0:
252			rem := int(hSig.RemainingTokens)
253			sig.QuotaRemaining = &rem
254		}
255		if !hSig.ResetTime.IsZero() {
256			t := hSig.ResetTime
257			sig.QuotaResetAt = &t
258		}
259	}
260	
261	// collectLocalSignal performs an HTTP GET /v1/models alive check for local
262	// providers. Local providers have no quota concept; only StatusAvailable vs
263	// StatusDegraded is determined.
264	func collectLocalSignal(ctx context.Context, baseURL string, sig *Signal) {
265		if baseURL == "" {
266			return // StatusUnknown
267		}
268		timeoutCtx, cancel := context.WithTimeout(ctx, aliveCheckTimeout)
269		defer cancel()
270	
271		checkURL := baseURL + "/v1/models"
272		req, err := http.NewRequestWithContext(timeoutCtx, http.MethodGet, checkURL, nil) // #nosec G107
273		if err != nil {
274			return // StatusUnknown; bad URL
275		}
276		resp, err := (&http.Client{}).Do(req)
277		if err != nil {
278			sig.Status = StatusDegraded
279			sig.LastErrorMsg = err.Error()
280			now := time.Now().UTC()
281			sig.LastErrorAt = &now
282			return
283		}
284		defer resp.Body.Close()
285	
286		if resp.StatusCode >= 200 && resp.StatusCode < 300 {
287			sig.Status = StatusAvailable
288			now := time.Now().UTC()
289			sig.LastSuccessAt = &now
290		} else {
291			sig.Status = StatusDegraded
292		}
293	}
294	
295	// ---- internal helpers -------------------------------------------------------
296	
297	func (s *Store) latencyWindow(provider string) *LatencyWindow {
298		s.mu.RLock()
299		win, ok := s.latencies[provider]
300		s.mu.RUnlock()
301		if ok {
302			return win
303		}
304		s.mu.Lock()
305		defer s.mu.Unlock()
306		if win, ok = s.latencies[provider]; ok {
307			return win
308		}
309		win = NewLatencyWindow(defaultWindowSize)
310		s.latencies[provider] = win
311		return win
312	}
